javascript:
frappe.query_reports["Configured Snapshot Diff"] = {
    filters: [
        {
            fieldname: "snapshot_a",
            label: __("Snapshot A (previous build)"),
            fieldtype: "Link",
            options: "Configured BOM Snapshot",
            reqd: 1,
        },
        {
            fieldname: "snapshot_b",
            label: __("Snapshot B (this build)"),
            fieldtype: "Link",
            options: "Configured BOM Snapshot",
            reqd: 1,
        },
        {
            fieldname: "view_mode",
            label: __("View Mode"),
            fieldtype: "Select",
            options: ["Hierarchical", "Flat Procurement"].join("\n"),
            default: "Hierarchical",
            reqd: 1,
        },
        {
            fieldname: "context_mode",
            label: __("Context"),
            fieldtype: "Select",
            options: ["Changes only", "Show full tree", "Show full list"].join("\n"),
            default: "Changes only",
        },
    ],

    formatter: function (value, row, column, data, default_formatter) {
        value = default_formatter(value, row, column, data);
        if (!data) return value;
        const status = (data._status_raw || "").toUpperCase();
        let bg = null;
        if (status === "ADDED") bg = "#DCFCE7";
        else if (status === "REMOVED") bg = "#FEE2E2";
        else if (status === "REVISION_CHANGED" || status === "CHANGED") bg = "#E0F2FE";
        else if (status === "QTY_CHANGED") bg = "#FEF9C3";
        else if (status === "MOVED") bg = "#F3E8FF";
        if (bg) {
            value = `<span style="display:block;margin:-4px -8px;padding:4px 8px;background:${bg};">${value}</span>`;
        }
        return value;
    },

    onload: function (report) {
        report.page.add_inner_button(__("Download Diff Workbook"), function () {
            const a = report.get_filter_value("snapshot_a");
            const b = report.get_filter_value("snapshot_b");
            const ctx = report.get_filter_value("context_mode");
            if (!a || !b) {
                frappe.msgprint(__("Select both snapshots first."));
                return;
            }
            const include_unchanged =
                (ctx === "Show full list" || ctx === "Show full tree") ? 1 : 0;
            const url =
                "/api/method/inductone_tools.snapshot_diff.loader.download_diff_workbook" +
                "?snapshot_a=" + encodeURIComponent(a) +
                "&snapshot_b=" + encodeURIComponent(b) +
                "&include_unchanged=" + include_unchanged;
            window.open(url);
        });
    },
};
